import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"不屈之拳","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/不屈之拳.md","filePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/不屈之拳.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/肉搏类/不屈之拳.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"不屈之拳",tabindex:"-1"},[s("不屈之拳 "),e("a",{class:"header-anchor",href:"#不屈之拳","aria-label":'Permalink to "不屈之拳"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),o('<h1 id="不屈之拳-1" tabindex="-1">不屈之拳 <a class="header-anchor" href="#不屈之拳-1" aria-label="Permalink to &quot;不屈之拳&quot;">​</a></h1><p>不屈之拳<br> 本质：特异<br> 技艺<br> 价格：C+1000<br> 前提：决心6<br> “我近百年的人生只教会我一件事，孩子，那就是不去祈祷在险恶中可以得到庇护，但要能无畏地面对险恶；不要取祈求痛苦会停止，但要相信自己能够征服它，我辈武者，真正的力量并非来自身体，而来自于不屈不挠的意志！”<br> 这是一名弱者临终前所开发的拳意，他本不应走上这条道路，矮小的身躯，孱弱的肢体，远不如人的天赋，唯一可称道的便是终其一生寄心于拳的坚持，一生无胜的耻辱本应牢牢的钉在他的墓碑上，直到他灯尽油枯，奄奄一息时，面对至强者所打出的最后一拳。<br> 【一生无胜，虽败犹荣】</p><p>效果：当人物面对展现出抵御绝望的不屈的意志，便可以决心代替力量进行不可留手的肉搏攻击检定。在场所有看到这一幕的生物，都会感受到这拳脚中所体现的坚傲的意志而对你肃然起敬（但不会影响态度，只是觉得你是一名值得尊重的武者）。若你因此进行的肉搏检定，成功命中目标，目标需要进行一次意志豁免与你本次攻击出目进行对抗，失败则目标会因感受到其中不灭的坚定意志，给予你作为武者最大的尊重，发挥全力与你堂堂正正的一战，本场战斗他将优先以你为攻击对象，这是c级心灵来源的胁迫影响的效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
